ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?degree_level ?certification ?job_post WHERE {
  ?degrees a :Degrees .
  ?degrees p:degree_level ?degree_level .
  ?degrees p:certification ?certification .
  ?degrees p:job_post ?job_post .
} }
  component: { SELECT ?degree_level ?job_post WHERE {
  ?degrees a :Degrees .
  ?degrees p:degree_level ?degree_level .
  ?degrees p:job_post ?job_post .
} }
  component_2: { SELECT ?certification ?job_post WHERE {
  ?degrees a :Degrees .
  ?degrees p:certification ?certification .
  ?degrees p:job_post ?job_post .
} }
}

PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?degree_level WHERE {
  ?degrees a :Degrees .
  ?degrees p:degree_level ?degree_level .
  ?degrees p:job_post ?job_post_f .
  FILTER(STR(?job_post_f) = "AI Researcher")
} }
  component_2: { SELECT ?certification WHERE {
  ?degrees a :Degrees .
  ?degrees p:certification ?certification .
  ?degrees p:job_post ?job_post_f .
  FILTER(STR(?job_post_f) = "AI Researcher")
} }
  full: { SELECT ?degree_level ?certification WHERE {
  ?degrees a :Degrees .
  ?degrees p:degree_level ?degree_level .
  ?degrees p:certification ?certification .
  ?degrees p:job_post ?job_post_f .
  FILTER(STR(?job_post_f) = "AI Researcher")
} }
}
